package commands

import (
	"context"
	"crypto/rand"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcUserTopicProgressRepository struct {
	sqrc db.Querier
}

func NewSqrcUserTopicProgressRepository(q db.Querier) *SqrcUserTopicProgressRepository {
	return &SqrcUserTopicProgressRepository{sqrc: q}
}

func (repository *SqrcUserTopicProgressRepository) getProgress(ctx context.Context, userId string, courseId string) (Progress, error) {
	var userIdUuid, courseIdUuid pgtype.UUID

	if err := userIdUuid.Scan(userId); err != nil {
		return Progress{}, err
	}
	if err := courseIdUuid.Scan(courseId); err != nil {
		return Progress{}, err
	}

	rows, err := repository.sqrc.GetProgressByUserIdAndCourseId(ctx, db.GetProgressByUserIdAndCourseIdParams{
		Userid:   userIdUuid,
		Courseid: courseIdUuid,
	})
	if err != nil {
		return Progress{}, err
	}

	records := make([]ProgressRecord, len(rows))
	for i, row := range rows {
		records[i] = ProgressRecord{
			userTopicProgressId:  row.UserTopicProgressID.String(),
			courseSectionId:      row.CourseSectionID.String(),
			courseSectionTopicId: row.CourseSectionTopicID.String(),
			status:               row.Status,
		}
	}

	return Progress{courseId: courseId, userId: userId, records: records}, nil
}

func (repository *SqrcUserTopicProgressRepository) save(ctx context.Context, progress *Progress) error {
	for _, record := range progress.records {
		progressIdUuid, err := generateUUID()
		if err != nil {
			return err
		}
		if record.userTopicProgressId != "" {
			if err := progressIdUuid.Scan(record.userTopicProgressId); err != nil {
				return err
			}
		}

		var courseIdUuid, sectionIdUuid, topicIdUuid, userIdUuid pgtype.UUID
		if err := courseIdUuid.Scan(progress.courseId); err != nil {
			return err
		}
		if err := sectionIdUuid.Scan(record.courseSectionId); err != nil {
			return err
		}
		if err := topicIdUuid.Scan(record.courseSectionTopicId); err != nil {
			return err
		}
		if err := userIdUuid.Scan(progress.userId); err != nil {
			return err
		}

		if err := repository.sqrc.UpsertProgress(ctx, db.UpsertProgressParams{
			Usertopicprogressid:  progressIdUuid,
			Courseid:             courseIdUuid,
			Coursesectionid:      sectionIdUuid,
			Coursesectiontopicid: topicIdUuid,
			Userid:               userIdUuid,
			Status:               record.status,
		}); err != nil {
			return err
		}
	}
	return nil
}

func generateUUID() (pgtype.UUID, error) {
	var u pgtype.UUID
	_, err := rand.Read(u.Bytes[:])
	if err != nil {
		return pgtype.UUID{}, err
	}
	u.Bytes[6] = (u.Bytes[6] & 0x0f) | 0x40
	u.Bytes[8] = (u.Bytes[8] & 0x3f) | 0x80
	u.Valid = true
	return u, nil
}

package commands

import (
	"context"
	"errors"
)

type EnrollCourseUsecaseParams struct {
	ctx           context.Context
	userId        string
	courseId      string
	sectionNumber *int
	topicNumber   *int
}

type EnrollCourseUsecase struct {
	courseRepository   CourseRepository
	progressRepository ProgressRepository
}

func NewEnrollCourseUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) EnrollCourseUsecase {
	return EnrollCourseUsecase{
		courseRepository:   courseRepo,
		progressRepository: progressRepo,
	}
}

type CourseRepository interface {
	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
}

type ProgressRepository interface {
	getProgress(ctx context.Context, userId string, courseId string) (Progress, error)
	save(ctx context.Context, progress *Progress) error
}

type EnrollCourseUsecaseInterface interface {
	execute(params EnrollCourseUsecaseParams) (string, error)
}

var ErrTopicNumberRequireSectionNumber = errors.New("topic number require section number")

func (usecase EnrollCourseUsecase) execute(params EnrollCourseUsecaseParams) (string, error) {
	course, err := usecase.courseRepository.getCourseByCourseId(params.ctx, params.courseId)
	if err != nil {
		return "", err
	}

	progress, err := usecase.progressRepository.getProgress(params.ctx, params.userId, params.courseId)
	if err != nil {
		return "", err
	}

	enrichProgressWithNumbers(&course, &progress)

	topicId, err := course.enroll(EnrollNumber{
		SectionNumber: params.sectionNumber,
		TopicNumber:   params.topicNumber,
	}, &progress)
	if err != nil {
		return "", err
	}

	return topicId, usecase.progressRepository.save(params.ctx, &progress)
}

func enrichProgressWithNumbers(course *Course, progress *Progress) {
	for i, record := range progress.records {
		for sIdx, section := range course.sections {
			for tIdx, topic := range section.topics {
				if topic.topicId == record.courseSectionTopicId {
					progress.records[i].sectionNumber = sIdx
					progress.records[i].topicNumber = tIdx
				}
			}
		}
	}
}

